+/// `[cursor=0, []]` reply mirroring upstream's shared.emptyscan,
+/// used when a collection scan targets a missing key.
+fn empty_scan_reply() -> RespFrame {
+    RespFrame::Array(Some(vec![
+        RespFrame::BulkString(Some(b"0".to_vec())),
+        RespFrame::Array(Some(vec![])),
+    ]))
+}
